/* ===========================================================================
 * Loading indicator while results are being fetched
 *
 * `render()` awaits the route's fetch (browse/search) before it can render a
 * table. During that in-flight window the results panel must NOT be blank — a
 * synchronous "Loading…" placeholder is committed BEFORE the first `await` so
 * the user sees that work is in progress instead of an empty/broken UI.
 *
 * The placeholder is set with `textContent` immediately after clearing any
 * stale table via `innerHTML = ''`, so it is in the DOM before any microtask
 * resolves the fetch. It is naturally replaced on success —
 * `renderBrowse`/`renderSearch` wipe `.results` and append the table — and on
 * error — the `catch` sets `.results.textContent` to the error message — so no
 * explicit cleanup is needed. These tests pin that contract for both dispatch
 * paths and for the synchronous "cleared-but-not-yet-fetched" window.
 * ========================================================================= */
describe('loading indicator while results are being fetched', () => {
  /**
   * Install a fetch stub whose BROWSE response for `heldPath` stays pending
   * until `release()` is invoked, mimicking a slow network so a test can
   * observe the in-flight UI. All other browse paths resolve immediately.
   */
  function holdBrowseFetch(heldPath: string): { release: () => void } {
    let release!: () => void;
    const held = new Promise<Response>((resolve) => {
      release = () =>
        resolve(
          mockResponse({
            body: browseResult({
              path: heldPath,
              entries: [
                fileEntry({
                  name: 'child-of-' + heldPath,
                  path: joinPathHelper(heldPath, 'child-of-' + heldPath),
                }),
              ],
              fileCount: 1,
              totalSize: 1,
            }),
          }),
        );
    });
    fetchMock.mockImplementation(async (url, init) => {
      const u = String(url);
      const method = (init?.method ?? 'GET').toUpperCase();
      if (method === 'GET' && u.includes('/browse')) {
        const path = decodeURIComponent(u.split('path=')[1] ?? '');
        if (path === heldPath) return held;
        return mockResponse({ body: browseResult({ path }) });
      }
      return mockResponse({ status: 200, body: {} });
    });
    return { release };
  }

  /**
   * Install a fetch stub whose SEARCH response for `heldQuery` stays pending
   * until `release()` is invoked. All other search queries resolve immediately.
   */
  function holdSearchFetch(heldQuery: string): { release: () => void } {
    let release!: () => void;
    const held = new Promise<Response>((resolve) => {
      release = () =>
        resolve(
          mockResponse({
            body: {
              query: heldQuery,
              path: '',
              results: [
                fileEntry({
                  name: 'result-for-' + heldQuery,
                  path: joinPathHelper('docs', 'result-for-' + heldQuery),
                }),
              ],
            } as SearchResult,
          }),
        );
    });
    fetchMock.mockImplementation(async (url, init) => {
      const u = String(url);
      const method = (init?.method ?? 'GET').toUpperCase();
      if (method === 'GET' && u.includes('/search')) {
        const afterQuery = u.slice(u.indexOf('query=') + 6);
        const query = decodeURIComponent(afterQuery.split('&')[0]);
        if (query === heldQuery) return held;
        return mockResponse({
          body: {
            query,
            path: '',
            results: [fileEntry({ name: 'result-for-' + query, path: joinPathHelper('docs', 'result-for-' + query) })],
          } as SearchResult,
        });
      }
      return mockResponse({ status: 200, body: {} });
    });
    return { release };
  }

  it('shows exactly "Loading…" in .results synchronously after startApp, before the fetch resolves', async () => {
    // render() runs up to its first `await` inside startApp, so by the time
    // setup() returns the placeholder is already committed. Asserting with no
    // intervening `await` pins that the placeholder is synchronous, and the
    // exact "Loading…" string pins the contract the UI relies on.
    const { results } = setup({ hash: toBrowseHash('home') });
    expect(results.textContent).toBe('Loading…');
    // No fetch microtask has resolved yet, so there is no table.
    expect(results.querySelector('table')).toBeNull();

    await flush();

    // Once the fetch resolves, the placeholder is replaced by the results table.
    expect(results.textContent).not.toContain('Loading');
    expect(results.textContent).toContain('child-of-home');
    expect(results.querySelector('table')).toBeTruthy();
  });

  it('shows "Loading…" in .results while a browse fetch is held in flight, then replaces it on success', async () => {
    const { release } = holdBrowseFetch('slow-folder');
    const { results } = setup({ hash: toBrowseHash('slow-folder') });

    // The fetch is held open → render() is suspended at its await. During this
    // window the panel must show the placeholder, not be blank.
    expect(results.textContent).toBe('Loading…');

    release();
    await flush();

    expect(results.textContent).not.toContain('Loading');
    expect(results.textContent).toContain('child-of-slow-folder');
    expect(results.querySelector('table')).toBeTruthy();
  });

  it('shows "Loading…" in .results while a search fetch is held in flight, then replaces it on success', async () => {
    const { release } = holdSearchFetch('slow-query');
    const { results } = setup({ hash: toSearchHash('slow-query', '') });

    expect(results.textContent).toBe('Loading…');

    release();
    await flush();

    expect(results.textContent).not.toContain('Loading');
    expect(results.textContent).toContain('result-for-slow-query');
    expect(results.querySelector('table')).toBeTruthy();
  });

  it('clears the stale table and shows "Loading…" in the same synchronous window, before the new fetch resolves', async () => {
    // Populate .results with a real table first (initial route settles), then
    // navigate to a route whose fetch is held. Synchronously after the navigate
    // — before the new fetch resolves — the OLD table must be gone AND the
    // placeholder must be visible. This pins the "after clearing, before fetch"
    // window the loading indicator exists to cover.
    const { release } = holdBrowseFetch('slow-folder');
    const { results } = setup({ hash: toBrowseHash('initial') });
    await flush();
    expect(results.querySelector('table')).toBeTruthy(); // stale table present

    navigate(toBrowseHash('slow-folder'));

    // Synchronous window after navigate, before the held fetch resolves:
    expect(results.querySelector('table')).toBeNull(); // stale table cleared
    expect(results.textContent).toBe('Loading…');      // placeholder shown

    release();
    await flush();

    expect(results.textContent).not.toContain('Loading');
    expect(results.textContent).toContain('child-of-slow-folder');
    expect(results.querySelector('table')).toBeTruthy();
  });

  it('replaces "Loading…" with the error message when the fetch fails', async () => {
    fetchMock.mockImplementation(async () => mockResponse({ status: 500, text: 'boom' }));
    const { results } = setup({ hash: toBrowseHash('home') });

    // While the failing fetch is still in flight, the placeholder is shown.
    expect(results.textContent).toBe('Loading…');

    await flush();

    // On error the placeholder is replaced by the existing error branch.
    expect(results.textContent).not.toContain('Loading');
    expect(results.textContent).toBe('Error: 500: boom');
    expect(results.querySelector('table')).toBeNull();
  });

  it('shows "Loading…" again on each navigation while the new fetch is pending', async () => {
    const { release } = holdBrowseFetch('slow-folder');
    const { results } = setup();
    await flush(); // settle the initial (default-route) render
    expect(results.textContent).not.toContain('Loading');

    navigate(toBrowseHash('slow-folder'));
    // hashchange fires synchronously in happy-dom → render() runs and hits the
    // held fetch. The placeholder must reappear for this new in-flight render.
    expect(results.textContent).toBe('Loading…');

    release();
    await flush();

    expect(results.textContent).not.toContain('Loading');
    expect(results.textContent).toContain('child-of-slow-folder');
    expect(results.querySelector('table')).toBeTruthy();
  });
});

