    // navigate() dispatches hashchange synchronously in happy-dom, so render()
    // runs up to its first `await` synchronously — clearing .results and
    // committing the "Loading…" placeholder, but NOT yet touching
    // breadcrumb/status.
    navigate(toBrowseHash('slow'));

    // The stale table is gone synchronously AND the "Loading…" placeholder is
    // committed in the same window, so the panel is not blank while the new
    // fetch is pending. (Assert via textContent — not children.length — because
    // the placeholder is a text node, not an element child.)
    expect(ctx.results.querySelector('table')).toBeNull();
    expect(ctx.results.textContent).toContain('Loading');
    // Breadcrumb + status are intentionally retained until the new data lands.
    expect(ctx.breadcrumb.innerHTML).toBe(oldBreadcrumbHtml);
    expect(ctx.status.textContent).toBe(oldStatusText);


